                <div className="bg-white rounded-[2.5rem] border border-slate-200 shadow-sm p-10 h-full">
                   <h4 className="text-[11px] font-black text-slate-400 uppercase tracking-[0.2em] mb-8 flex items-center gap-2">
                      <Crosshair className="w-5 h-5 text-rose-500" /> 动态战术地图 (Tactical Map)
                   </h4>
                   <div className="grid grid-cols-1 md:grid-cols-2 gap-10">
                      <div className="space-y-8">
                         <div className="relative pl-6 border-l-4 border-rose-500">
                            <div className="text-[10px] font-black text-slate-400 uppercase mb-1">量化介入点 (Entry)</div>
                            <div className="text-3xl font-black text-slate-800 tracking-tight">{auditData.execution_model.entry_anchor}</div>
                         </div>
                         <div className="relative pl-6 border-l-4 border-emerald-500">
                            <div className="text-[10px] font-black text-slate-400 uppercase mb-1">算法离场位 (Exit)</div>
                            <div className="text-3xl font-black text-slate-800 tracking-tight">{auditData.execution_model.exit_anchor}</div>
                         </div>
                      </div>
                      <div className="bg-slate-50 rounded-[2rem] p-8 border border-slate-100">
                         <div className="text-[10px] font-black text-rose-600 uppercase tracking-widest mb-2">止损防御</div>
                         <div className="text-2xl font-black text-slate-800 mb-4">{auditData.execution_model.stop_loss}</div>
                         <p className="text-xs text-slate-500 font-bold">{auditData.market_cohesion.verdict}</p>
                      </div>
                   </div>
                </div>
             </div>
          </div>
        </div>
      )}

      {/* Empty State */}
      {!result && !loading && (
        <div className="py-40 text-center flex flex-col items-center justify-center bg-white rounded-[3rem] border border-dashed border-slate-200">
           <Radar className="w-20 h-20 text-indigo-100 mb-8 animate-pulse" />
           <p className="text-slate-400 font-black text-2xl tracking-tight">
             {mode === 'discover' ? '算法猎手已就绪，准备扫描全网标的' : '输入代码或上传分时图进行合力审计'}
           </p>
           <p className="text-slate-300 text-sm mt-4 max-w-lg mx-auto leading-relaxed">
             AI 将实时探测市场上量化资金最密集的“战场”，助您捕捉主力算法留下的黄金机会。
           </p>
        </div>
      )}
    </div>
  );
};

