const robustParse = (text: string): any => {
  if (!text) return null;
  let clean = text.trim();
  clean = clean.replace(/^```[a-z]*\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/, '');
  const firstBrace = clean.search(/[{[]/);
  const lastCurly = clean.lastIndexOf('}');
  const lastSquare = clean.lastIndexOf(']');
  const lastIndex = Math.max(lastCurly, lastSquare);
  if (firstBrace !== -1 && lastIndex !== -1 && lastIndex > firstBrace) {
    clean = clean.substring(firstBrace, lastIndex + 1);
  }
  try {
    return JSON.parse(clean);
  } catch (e) {
    return null;
  }
};

/**
 * UPDATED: 强化板块合力嗅探
 */
export const discoverQuantSynergy = async (apiKey: string): Promise<AnalysisResult> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const now = new Date();
  const timeContext = now.toLocaleString('zh-CN');

  const prompt = `
    【核心指令：A股量化“兵团作战”与板块合力进攻嗅探】
    当前时间: ${timeContext}。

    任务：作为顶级量化猎手，利用 googleSearch 实时扫描 A 股市场，锁定“量化资金扎堆进攻”的板块战场。
    我们要寻找的是【板块共振】现象：
    1. **板块合力分析**：寻找那些全板块标的同步放量、形态高度一致（如：齐涨、齐拉升）的区域。这种现象通常是量化算法在集体扫货。
    2. **领涨点火者 vs 跟随者**：识别谁是板块的算法先行者，谁是正在同步启动的补涨者。
    3. **资金高潮点**：检索今日被算法猛攻的板块（如：AI服务器、低空经济、半导体某细分），计算其板块协同度（sector_cohesion_level）。

    [输出要求]：
    - quant_cluster_sectors: 找出今日量化进攻最猛烈的 3 个板块，描述进攻强度和同步变动的核心标的（hot_peers）。
    - top_targets: 在这些猛攻板块中，选出 5-8 只最有进攻价值的标的，明确其是否为板块领涨（is_sector_leader）。

    输出严格 JSON。
  `;

  const response = await ai.models.generateContent({
    model: GEMINI_MODEL_PRIMARY,
    contents: prompt,
    config: { 
      tools: [{ googleSearch: {} }], 
      responseMimeType: "application/json", 
      responseSchema: quantDiscoverySchema 
    }
  });
  const parsed = robustParse(response.text || "{}");
  return { 
    content: response.text || "", 
    timestamp: Date.now(), 
    modelUsed: ModelProvider.GEMINI_INTL, 
    isStructured: true, 
    quantDiscoveryData: parsed, 
    market: MarketType.CN 
  };
};

