const robustParse = (text: string): any => {
  if (!text) return null;
  let clean = text.trim();
  clean = clean.replace(/^```[a-z]*\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/, '');
  const firstBrace = clean.search(/[{[]/);
  const lastCurly = clean.lastIndexOf('}');
  const lastSquare = clean.lastIndexOf(']');
  const lastIndex = Math.max(lastCurly, lastSquare);
  if (firstBrace !== -1 && lastIndex !== -1 && lastIndex > firstBrace) {
    clean = clean.substring(firstBrace, lastIndex + 1);
  }
  try {
    return JSON.parse(clean);
  } catch (e) {
    return null;
  }
};

/**
 * 升级版：主升战术复刻服务 (集成“金海通”与“大位科技”成败对比逻辑)
 */
export const replicateMainWaveTactic = async (apiKey: string): Promise<AnalysisResult> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const now = new Date();
  const timeContext = now.toLocaleString('zh-CN');

  const prompt = `
    【核心指令：复刻“金海通”模式 —— 寻找机构背书的主升中继黑马】
    当前时间: ${timeContext}。

    [用户实战教训注入]：
    1. **正向案例 (金海通)**：机构调研支撑、主升浪已经走出一截(180-240)、14:30 尾盘确认强度后介入。即使股价高，只要逻辑未变、量能持续，就是好标的。
    2. **负面案例 (大位科技)**：早盘冲动买入、被诱多、无尾盘确认逻辑，导致割肉。

    [任务要求]：利用 googleSearch 检索最新的【机构一手资料/调研纪要】，筛选符合以下特征的标的：
    - **打破恐高心理**：筛选股价虽高但处于主升浪中继（如金海通当时 180-240 的位置）且不缩量的标的。
    - **2:30 准则评估**：针对当前接近收盘的时间，评估其是否能封死涨停或维持高位稳健（即“真突破”）。
    - **做T潜力**：振幅需满足日内 T+0 空间，计算支撑位与压力位。

    输出必须严格 JSON。
  `;

  const response = await ai.models.generateContent({
    model: GEMINI_MODEL_PRIMARY,
    contents: prompt,
    config: { 
      tools: [{ googleSearch: {} }], 
      responseMimeType: "application/json", 
      responseSchema: mainWaveSchema 
    }
  });
  const parsed = robustParse(response.text || "{}");
  return { 
    content: response.text || "", 
    timestamp: Date.now(), 
    modelUsed: ModelProvider.GEMINI_INTL, 
    isStructured: true, 
    mainWaveData: parsed, 
    market: MarketType.CN 
  };
};

