import React, { useState, useEffect, useRef } from 'react';
import { ModelProvider, AnalysisResult, UserSettings, MarketType, HoldingsSnapshot, HoldingItemDetailed, JournalEntry, DailyTradingPlan } from '../types';
import { analyzeWithLLM } from '../services/llmAdapter';
import { parseBrokerageScreenshot } from '../services/geminiService';
import { analyzeImageWithExternal } from '../services/externalLlmService';
import { Loader2, Save, Download, UploadCloud, History, Trash2, Camera, X, FileJson, TrendingUp, AlertTriangle, Activity, Target, Clock, Trophy, AlertOctagon, CheckCircle2, XCircle, ListTodo, FileText, FileSpreadsheet, FileCode, ChevronLeft, ChevronRight, AlertCircle, ShieldAlert, Microscope, FileType, ShieldX, Zap, Import } from 'lucide-react';

interface HoldingsReviewProps {
  currentModel: ModelProvider;
  currentMarket: MarketType;
  settings: UserSettings;
  onOpenSettings?: () => void;
}

export const HoldingsReview: React.FC<HoldingsReviewProps> = ({
  currentModel,
  currentMarket,
  settings,
  onOpenSettings
}) => {
  // --- State ---
  const [snapshot, setSnapshot] = useState<HoldingsSnapshot>({
    totalAssets: 0,
    positionRatio: 0, 
    date: new Date().toISOString().split('T')[0],
    holdings: []
  });

  const [journal, setJournal] = useState<JournalEntry[]>(() => {
    const saved = localStorage.getItem('qm_journal');
    if (!saved) return [];
    try {
      return JSON.parse(saved);
    } catch (e) {
      return [];
    }
  });

  const [analysisResult, setAnalysisResult] = useState<AnalysisResult | null>(null);
  const [loading, setLoading] = useState(false);
  const [parsing, setParsing] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [isHistoryOpen, setIsHistoryOpen] = useState(false);
  const [isPlanOpen, setIsPlanOpen] = useState(false);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const importInputRef = useRef<HTMLInputElement>(null);

  // --- Core Handlers ---

  // 保存当前审计到历史
  const saveToJournal = () => {
    if (!analysisResult || snapshot.holdings.length === 0) return;
    const newEntry: JournalEntry = {
      id: `jr_${Date.now()}`,
      timestamp: Date.now(),
      snapshot: { ...snapshot },
      analysis: { ...analysisResult },
      note: "自动保存的复盘报告"
    };
    const updated = [newEntry, ...journal];
    setJournal(updated);
    localStorage.setItem('qm_journal', JSON.stringify(updated));
    alert("审计报告已存入历史日志。");
  };

  // 还原历史快照
  const restoreFromHistory = (entry: JournalEntry) => {
    setSnapshot(entry.snapshot);
    setAnalysisResult(entry.analysis);
    setIsHistoryOpen(false);
    window.scrollTo({ top: 400, behavior: 'smooth' });
  };

  // 导出全部数据
  const exportJournal = () => {
    const dataStr = JSON.stringify(journal, null, 2);
    const dataUri = 'data:application/json;charset=utf-8,'+ encodeURIComponent(dataStr);
    const exportFileDefaultName = `QuantMind_Journal_${new Date().toISOString().split('T')[0]}.json`;
    const linkElement = document.createElement('a');
    linkElement.setAttribute('href', dataUri);
    linkElement.setAttribute('download', exportFileDefaultName);
    linkElement.click();
  };

  // 导入数据
  const handleImport = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const imported = JSON.parse(event.target?.result as string);
        if (Array.isArray(imported)) {
          const combined = [...imported, ...journal].filter((v, i, a) => a.findIndex(t => t.id === v.id) === i);
          setJournal(combined);
          localStorage.setItem('qm_journal', JSON.stringify(combined));
          alert(`成功导入 ${imported.length} 条历史记录。`);
        }
      } catch (err) {
        alert("导入失败：文件格式不正确。");
      }
    };
    reader.readAsText(file);
  };

  const handleImageUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setParsing(true);
    setError(null);
    try {
      const reader = new FileReader();
      reader.onloadend = async () => {
        const base64String = (reader.result as string).split(',')[1];
        let parsedData: HoldingsSnapshot;
        if (currentModel === ModelProvider.HUNYUAN_CN) {
           parsedData = await analyzeImageWithExternal(ModelProvider.HUNYUAN_CN, base64String, settings.hunyuanKey!);
        } else {
           parsedData = await parseBrokerageScreenshot(base64String, settings.geminiKey);
        }
        setSnapshot({
          ...parsedData,
          holdings: parsedData.holdings.map(h => ({ ...h, horizon: 'medium' })),
          date: new Date().toISOString().split('T')[0] 
        });
      }
      reader.readAsDataURL(file);
    } catch (err: any) { setError(err.message); } finally { setParsing(false); }
  };

  const handleAnalyze = async () => {
    if (snapshot.holdings.length === 0) return;
    setLoading(true);
    setAnalysisResult(null);
    setError(null);

    const prompt = `
      请作为我的私人量化顾问，对我当前的持仓进行【深度复盘审计】。
      历史悲剧警戒：
      1. 利润回撤防控 (参考 1.12 惨剧)。
      2. 2:30 尾盘确认准则。
      3. 标的精简度（严控在 3 只以内）。
      数据：${JSON.stringify(snapshot)}
    `;

    try {
      const result = await analyzeWithLLM(currentModel, prompt, true, settings, false, 'day', undefined, currentMarket);
      setAnalysisResult(result);
    } catch (err: any) { setError(err.message); } finally { setLoading(false); }
  };

  return (
    <div className="space-y-6 animate-fade-in pb-20">

      {/* 红线警示卡片 */}
