import React, { useState, useEffect, useRef } from 'react';
import { ModelProvider, AnalysisResult, UserSettings, MarketType, HoldingsSnapshot, HoldingItemDetailed, JournalEntry, DailyTradingPlan } from '../types';
import { analyzeWithLLM } from '../services/llmAdapter';
import { parseBrokerageScreenshot } from '../services/geminiService';
import { analyzeImageWithExternal } from '../services/externalLlmService';
import { Loader2, Save, Download, UploadCloud, History, Trash2, Camera, X, FileJson, TrendingUp, AlertTriangle, Activity, Target, Clock, Trophy, AlertOctagon, CheckCircle2, XCircle, ListTodo, FileText, FileSpreadsheet, FileCode, ChevronLeft, ChevronRight, AlertCircle, ShieldAlert, Microscope, FileType, ShieldX, Zap, Import, ClipboardPaste } from 'lucide-react';

interface HoldingsReviewProps {
  currentModel: ModelProvider;
  currentMarket: MarketType;
  settings: UserSettings;
  onOpenSettings?: () => void;
}

export const HoldingsReview: React.FC<HoldingsReviewProps> = ({
  currentModel,
  currentMarket,
  settings,
  onOpenSettings
}) => {
  // --- State ---
  const [snapshot, setSnapshot] = useState<HoldingsSnapshot>({
    totalAssets: 0,
    positionRatio: 0, 
    date: new Date().toISOString().split('T')[0],
    holdings: []
  });

  const [journal, setJournal] = useState<JournalEntry[]>(() => {
    const saved = localStorage.getItem('qm_journal');
    if (!saved) return [];
    try {
      return JSON.parse(saved);
    } catch (e) {
      return [];
    }
  });

  const [analysisResult, setAnalysisResult] = useState<AnalysisResult | null>(null);
  const [loading, setLoading] = useState(false);
  const [parsing, setParsing] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [isHistoryOpen, setIsHistoryOpen] = useState(false);
  const [importText, setImportText] = useState('');
  const [isImportTextOpen, setIsImportTextOpen] = useState(false);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const importInputRef = useRef<HTMLInputElement>(null);

  // --- Core Handlers ---

  // 标准化数据（处理 positionRatio 格式不统一问题）
  const normalizeData = (data: any[]): JournalEntry[] => {
    return data.map(item => {
      const newItem = { ...item };
      // 处理 positionRatio
      if (newItem.snapshot && typeof newItem.snapshot.positionRatio === 'number') {
        // 如果是 0.858 这种格式，转换为 85.8
        if (newItem.snapshot.positionRatio > 0 && newItem.snapshot.positionRatio < 1.5) {
          newItem.snapshot.positionRatio = Number((newItem.snapshot.positionRatio * 100).toFixed(2));
        }
      }
      return newItem as JournalEntry;
    });
  };

  // 保存当前审计到历史
  const saveToJournal = () => {
    if (!analysisResult || snapshot.holdings.length === 0) return;
    const newEntry: JournalEntry = {
      id: `jr_${Date.now()}`,
      timestamp: Date.now(),
      snapshot: { ...snapshot },
      analysis: { ...analysisResult },
      note: "手动保存"
    };
    const updated = [newEntry, ...journal];
    setJournal(updated);
    localStorage.setItem('qm_journal', JSON.stringify(updated));
    alert("审计报告已成功封存至历史日志。");
  };

  // 还原历史快照
  const restoreFromHistory = (entry: JournalEntry) => {
    // 还原时再次确保数据标准化
    const normalizedSnapshot = { ...entry.snapshot };
    if (normalizedSnapshot.positionRatio < 1.5 && normalizedSnapshot.positionRatio > 0) {
      normalizedSnapshot.positionRatio = Number((normalizedSnapshot.positionRatio * 100).toFixed(2));
    }

    setSnapshot(normalizedSnapshot);
    setAnalysisResult(entry.analysis);
    setIsHistoryOpen(false);
    window.scrollTo({ top: 400, behavior: 'smooth' });
    alert(`已还原 ${normalizedSnapshot.date} 的持仓快照。您可以基于此数据进行二次对比或审计。`);
  };

  // 导入数据处理逻辑
  const processImportedData = (data: any) => {
    try {
      const rawArray = Array.isArray(data) ? data : [data];
      const normalized = normalizeData(rawArray);

      // 合并并去重
      const combined = [...normalized, ...journal].filter(
        (v, i, a) => a.findIndex(t => t.id === v.id || (t.timestamp === v.timestamp && t.snapshot?.date === v.snapshot?.date)) === i
      );

      setJournal(combined);
      localStorage.setItem('qm_journal', JSON.stringify(combined));
      alert(`成功同步 ${normalized.length} 条历史复盘记录。`);
      setIsImportTextOpen(false);
      setImportText('');
    } catch (err) {
      console.error(err);
      alert("解析失败：请确保 JSON 格式符合要求。");
    }
  };

  // 文件导入
  const handleFileImport = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const json = JSON.parse(event.target?.result as string);
        processImportedData(json);
      } catch (err) {
        alert("文件读取失败，非标准 JSON。");
      }
    };
    reader.readAsText(file);
  };

  // 文本导入
  const handleTextImport = () => {
    try {
      const json = JSON.parse(importText);
      processImportedData(json);
    } catch (e) {
      alert("JSON 格式错误，请检查。");
    }
  };

  const handleImageUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setParsing(true);
    setError(null);
    try {
      const reader = new FileReader();
      reader.onloadend = async () => {
        const base64String = (reader.result as string).split(',')[1];
        let parsedData: HoldingsSnapshot;
        if (currentModel === ModelProvider.HUNYUAN_CN) {
           parsedData = await analyzeImageWithExternal(ModelProvider.HUNYUAN_CN, base64String, settings.hunyuanKey!);
        } else {
           parsedData = await parseBrokerageScreenshot(base64String, settings.geminiKey);
        }
        setSnapshot({
          ...parsedData,
          holdings: parsedData.holdings.map(h => ({ ...h, horizon: 'medium' })),
          date: new Date().toISOString().split('T')[0] 
        });
      }
      reader.readAsDataURL(file);
    } catch (err: any) { setError(err.message); } finally { setParsing(false); }
  };

  const handleAnalyze = async () => {
    if (snapshot.holdings.length === 0) return;
    setLoading(true);
    setAnalysisResult(null);
    setError(null);

    const prompt = `
      请作为我的私人量化顾问，对我当前的持仓进行【深度复盘审计】。
      历史悲剧警戒：
      1. 利润回撤防控 (参考 1.12 惨剧)。
      2. 2:30 尾盘确认准则。
      3. 标的精简度（严控在 3 只以内）。
      当前持仓数据：${JSON.stringify(snapshot)}
    `;

    try {
      const result = await analyzeWithLLM(currentModel, prompt, true, settings, false, 'day', undefined, currentMarket);
      setAnalysisResult(result);
    } catch (err: any) { setError(err.message); } finally { setLoading(false); }
  };

  return (
    <div className="space-y-6 animate-fade-in pb-20">

      {/* 2月实战红线警示 */}
      <div className="bg-gradient-to-r from-rose-900 to-slate-900 rounded-[2.5rem] p-8 text-white shadow-2xl border-l-[12px] border-rose-500 relative overflow-hidden">
         <div className="absolute right-0 top-0 opacity-10 pointer-events-none">
            <ShieldX className="w-64 h-64 -mr-16 -mt-16" />
         </div>
         <div className="relative z-10">
            <div className="flex items-center gap-3 mb-4">
               <span className="px-3 py-1 bg-rose-600 text-white text-[10px] font-black rounded uppercase tracking-widest animate-pulse">2 月实战红线</span>
               <span className="text-slate-400 text-xs font-bold italic">“记住 1.12 的最高点回撤，不要在人声鼎沸时贪婪”</span>
            </div>
            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
               <div className="bg-white/5 backdrop-blur-md p-4 rounded-2xl border border-white/10">
                  <div className="flex items-center gap-2 text-rose-400 font-black text-xs mb-2 uppercase"><Clock className="w-4 h-4" /> 2:30 准则</div>
                  <p className="text-xs font-bold text-slate-200">早盘禁止任何冲动介入。必须在 **14:30** 之后观察企稳后再定夺。</p>
               </div>
               <div className="bg-white/5 backdrop-blur-md p-4 rounded-2xl border border-white/10">
                  <div className="flex items-center gap-2 text-amber-400 font-black text-xs mb-2 uppercase"><Target className="w-4 h-4" /> 极简头寸</div>
                  <p className="text-xs font-bold text-slate-200">标的严禁超过 **3 只**。一只核心，两只机动，确保精力不被分散。</p>
               </div>
               <div className="bg-white/5 backdrop-blur-md p-4 rounded-2xl border border-white/10">
                  <div className="flex items-center gap-2 text-emerald-400 font-black text-xs mb-2 uppercase"><Zap className="w-4 h-4" /> 利润回撤线</div>
                  <p className="text-xs font-bold text-slate-200">最高点回撤超过 **10%** 强制止盈一半。杜绝 1 月中旬利润吐出过半的悲剧。</p>
               </div>
            </div>
         </div>
      </div>

      {/* 控制中心 */}
      <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6 no-print">
        <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4 mb-6">
          <div>
            <h2 className="text-xl font-bold text-slate-800 flex items-center gap-2">
              <UploadCloud className="w-6 h-6 text-indigo-600" />
              持仓审计与利润守卫
            </h2>
            <p className="text-sm text-slate-500 mt-1">AI 已硬核加载您的“2:30 确认准则”与“1.12 止盈警戒线”。</p>
          </div>
          <div className="flex flex-wrap gap-2">
            <button onClick={() => setIsHistoryOpen(true)} className="flex items-center gap-2 px-3 py-2 text-sm font-bold text-slate-600 bg-slate-100 rounded-lg border border-slate-200 hover:bg-slate-200 transition-all shadow-sm">
              <History className="w-4 h-4" /> 历史日志
            </button>
            <input type="file" accept="image/*" ref={fileInputRef} className="hidden" onChange={handleImageUpload} />
            <button onClick={() => fileInputRef.current?.click()} className="flex items-center gap-2 px-4 py-2 bg-indigo-600 hover:bg-indigo-700 text-white rounded-lg font-bold transition-all shadow-md active:scale-95">
              {parsing ? <Loader2 className="w-4 h-4 animate-spin" /> : <Camera className="w-4 h-4" />}
