           >
             {loading ? <Loader2 className="w-5 h-5 animate-spin" /> : <ShieldAlert className="w-5 h-5" />}
             {loading ? 'AI 正基于血泪教训审计中...' : '启动“利润留存”实战复盘'}
           </button>
        </div>
      </div>

      {/* 审计报告展示 */}
      {analysisResult && (
        <div className="bg-white rounded-[2.5rem] border border-slate-200 shadow-sm overflow-hidden animate-slide-up">
           <div className="bg-slate-900 px-8 py-5 flex justify-between items-center">
              <div className="flex items-center gap-3">
                 <div className="p-2 bg-rose-600 rounded-lg"><Microscope className="w-5 h-5 text-white"/></div>
                 <h3 className="text-white font-black">AI 量化规则审计报告</h3>
              </div>
              <div className="flex gap-2">
                 <button onClick={saveToJournal} className="flex items-center gap-2 px-4 py-1.5 bg-indigo-600 text-white text-xs font-black rounded-lg hover:bg-indigo-700 transition-all border border-indigo-500">
