              <div className="px-8 py-6 border-b border-slate-100 bg-slate-50 flex justify-between items-center">
                 <div>
                    <h3 className="text-xl font-black text-slate-800 flex items-center gap-3">
                        <History className="w-6 h-6 text-indigo-600" />
                        实战审计黑匣子
                    </h3>
                    <p className="text-xs text-slate-500 font-bold mt-1">您可以导入 1 月份的 JSON 日志，随时还原快照进行复盘对比。</p>
                 </div>
                 <div className="flex gap-2">
                    <button onClick={() => setIsImportTextOpen(true)} className="flex items-center gap-2 px-4 py-2 bg-white text-slate-700 rounded-xl text-xs font-black border border-slate-200 hover:bg-slate-50 transition-all">
                       <ClipboardPaste className="w-4 h-4" /> 粘贴 JSON 导入
                    </button>
                    <input type="file" ref={importInputRef} className="hidden" accept=".json" onChange={handleFileImport} />
                    <button onClick={() => importInputRef.current?.click()} className="flex items-center gap-2 px-4 py-2 bg-indigo-50 text-indigo-600 rounded-xl text-xs font-black border border-indigo-100 hover:bg-indigo-100 transition-all">
                       <Import className="w-4 h-4" /> 文件导入
                    </button>
                    <button onClick={() => {
                        const dataStr = JSON.stringify(journal, null, 2);
                        const dataUri = 'data:application/json;charset=utf-8,'+ encodeURIComponent(dataStr);
                        const link = document.createElement('a');
                        link.setAttribute('href', dataUri);
                        link.setAttribute('download', `QuantMind_Full_Backup_${new Date().toISOString().split('T')[0]}.json`);
                        link.click();
                    }} className="flex items-center gap-2 px-4 py-2 bg-slate-900 text-white rounded-xl text-xs font-black hover:bg-black transition-all">
                       <Download className="w-4 h-4" /> 全量备份导出
                    </button>
                    <button onClick={() => setIsHistoryOpen(false)} className="p-2 text-slate-400 hover:text-slate-600 transition-colors ml-4">
                       <X className="w-6 h-6" />
                    </button>
                 </div>
              </div>

              <div className="p-8 overflow-y-auto flex-1 bg-slate-50/50">
                 {journal.length === 0 ? (
                    <div className="py-20 text-center flex flex-col items-center gap-4">
                        <FileCode className="w-16 h-16 text-slate-200" />
                        <p className="text-slate-400 font-bold">暂无历史记录。建议点击“从剪贴板导入”还原您之前的 1 月日志。</p>
                    </div>
                 ) : (
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                       {journal.map((entry) => (
                          <div key={entry.id} className="group p-6 bg-white rounded-[2rem] border border-slate-200 hover:border-indigo-400 hover:shadow-xl transition-all flex flex-col justify-between">
                             <div className="mb-4">
                                <div className="flex justify-between items-start mb-4">
                                   <div className="text-center bg-indigo-50 w-14 h-14 rounded-2xl border border-indigo-100 flex flex-col justify-center">
                                      <div className="text-[10px] font-black text-indigo-400 uppercase tracking-tighter">{new Date(entry.timestamp).getMonth()+1}月</div>
                                      <div className="text-xl font-black text-indigo-600">{new Date(entry.timestamp).getDate()}</div>
                                   </div>
                                   <div className="text-right">
                                      <div className="text-sm font-black text-slate-800">¥ {entry.snapshot?.totalAssets?.toLocaleString() || '0'}</div>
                                      <div className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">{entry.snapshot?.date} 快照</div>
                                   </div>
                                </div>
                                <div className="space-y-1.5 mb-4">
                                   {entry.snapshot?.holdings?.slice(0, 3).map((h: any, i: number) => (
                                      <div key={i} className="flex justify-between text-xs font-medium">
                                         <span className="text-slate-600">{h.name}</span>
                                         <span className={h.profit >= 0 ? 'text-rose-500' : 'text-emerald-500'}>{h.profitRate}</span>
                                      </div>
                                   ))}
                                   {entry.snapshot?.holdings?.length > 3 && <div className="text-[9px] text-slate-400 italic">及其他 {entry.snapshot.holdings.length - 3} 只标的...</div>}
                                </div>
                             </div>
                             <div className="flex gap-2">
                                <button 
                                   onClick={() => restoreFromHistory(entry)}
                                   className="flex-1 py-2.5 bg-indigo-600 text-white text-xs font-black rounded-xl shadow-lg hover:bg-indigo-700 transition-all flex items-center justify-center gap-2"
                                >
                                   还原并对比逻辑 <ChevronRight className="w-4 h-4" />
                                </button>
                                <button 
                                   onClick={() => {
                                      if(confirm("确定要删除这条珍贵的实战记录吗？")) {
                                        const updated = journal.filter(j => j.id !== entry.id);
                                        setJournal(updated);
                                        localStorage.setItem('qm_journal', JSON.stringify(updated));
                                      }
                                   }}
                                   className="p-2.5 text-slate-300 hover:text-rose-500 transition-colors bg-slate-50 rounded-xl border border-slate-100"
                                >
                                   <Trash2 className="w-4 h-4" />
                                </button>
                             </div>
                          </div>
                       ))}
                    </div>
                 )}
              </div>
           </div>
        </div>
      )}

      {/* 文本导入 Modal */}
      {isImportTextOpen && (
        <div className="fixed inset-0 z-[110] flex items-center justify-center p-4 bg-slate-900/40 backdrop-blur-sm animate-fade-in">
           <div className="bg-white rounded-[2.5rem] shadow-2xl w-full max-w-2xl overflow-hidden flex flex-col">
              <div className="px-8 py-6 border-b border-slate-100 flex justify-between items-center">
                 <h3 className="text-lg font-black text-slate-800">直接粘贴 JSON 数据同步</h3>
                 <button onClick={() => setIsImportTextOpen(false)}><X className="w-5 h-5 text-slate-400"/></button>
              </div>
              <div className="p-8">
                 <textarea 
                   value={importText}
                   onChange={e => setImportText(e.target.value)}
                   placeholder="请在此粘贴 1 月份的历史日志 JSON 数据..."
                   className="w-full h-64 p-4 bg-slate-50 border border-slate-200 rounded-2xl font-mono text-xs outline-none focus:ring-4 focus:ring-indigo-50 transition-all"
                 />
                 <div className="mt-6 flex gap-3">
                    <button onClick={handleTextImport} className="flex-1 py-4 bg-indigo-600 text-white font-black rounded-2xl shadow-xl hover:bg-indigo-700 transition-all">立即同步数据</button>
                    <button onClick={() => setIsImportTextOpen(false)} className="px-8 py-4 bg-slate-100 text-slate-600 font-black rounded-2xl">取消</button>
                 </div>
              </div>
           </div>
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { ModelProvider, AnalysisResult, UserSettings, MarketType, HoldingsSnapshot, HoldingItemDetailed, JournalEntry, DailyTradingPlan } from '../types';
import { analyzeWithLLM } from '../services/llmAdapter';
import { parseBrokerageScreenshot } from '../services/geminiService';
import { analyzeImageWithExternal } from '../services/externalLlmService';
import { Loader2, Save, Download, UploadCloud, History, Trash2, Camera, X, FileJson, TrendingUp, Activity, Target, Clock, Trophy, AlertOctagon, CheckCircle2, XCircle, ListTodo, FileText, FileSpreadsheet, FileCode, ChevronLeft, ChevronRight, AlertCircle, ShieldAlert, Microscope, FileType, ShieldX, Zap, Import, ClipboardPaste, ScanSearch, CheckCircle, Sparkles, Database } from 'lucide-react';

interface HoldingsReviewProps {
  currentModel: ModelProvider;
  currentMarket: MarketType;
  settings: UserSettings;
  onOpenSettings?: () => void;
}

export const HoldingsReview: React.FC<HoldingsReviewProps> = ({
  currentModel,
  currentMarket,
  settings,
  onOpenSettings
}) => {
  // --- State ---
  const [snapshot, setSnapshot] = useState<HoldingsSnapshot>({
    totalAssets: 0,
    positionRatio: 0, 
    date: new Date().toISOString().split('T')[0],
    holdings: []
  });

  const [journal, setJournal] = useState<JournalEntry[]>(() => {
    const saved = localStorage.getItem('qm_journal');
    if (!saved) return [];
    try {
      return JSON.parse(saved);
    } catch (e) {
      return [];
    }
  });

  const [analysisResult, setAnalysisResult] = useState<AnalysisResult | null>(null);
  const [loading, setLoading] = useState(false);
  const [parsing, setParsing] = useState(false);
  const [parsingPhase, setParsingPhase] = useState("");
  const [showSuccessTip, setShowSuccessTip] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [isHistoryOpen, setIsHistoryOpen] = useState(false);
  const [importText, setImportText] = useState('');
  const [isImportTextOpen, setIsImportTextOpen] = useState(false);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const importInputRef = useRef<HTMLInputElement>(null);
  const tableRef = useRef<HTMLDivElement>(null);

  // --- Handlers ---

  const handleImageUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setParsing(true);
    setError(null);
    setShowSuccessTip(false);

    // 模拟识别阶段
    setParsingPhase("正在启动多模态视觉引擎...");

    try {
      const reader = new FileReader();
      reader.onloadend = async () => {
        const base64String = (reader.result as string).split(',')[1];

        setParsingPhase("正在识别截图中的证券列表与资产总额...");
        let parsedData: HoldingsSnapshot;
        if (currentModel === ModelProvider.HUNYUAN_CN) {
           parsedData = await analyzeImageWithExternal(ModelProvider.HUNYUAN_CN, base64String, settings.hunyuanKey!);
        } else {
           parsedData = await parseBrokerageScreenshot(base64String, settings.geminiKey);
        }

        setParsingPhase("识别成功！正在同步全网实时行情...");

        setTimeout(() => {
          setSnapshot({
            ...parsedData,
            holdings: parsedData.holdings.map(h => ({ ...h, horizon: 'medium' })),
            date: new Date().toISOString().split('T')[0] 
          });
          setParsing(false);
          setShowSuccessTip(true);
          // 自动滚动到列表
          tableRef.current?.scrollIntoView({ behavior: 'smooth', block: 'center' });
        }, 800);
      }
      reader.readAsDataURL(file);
    } catch (err: any) { 
      setError(err.message); 
      setParsing(false);
    }
  };

  const handleAnalyze = async () => {
    if (snapshot.holdings.length === 0) return;
    setLoading(true);
    setAnalysisResult(null);
    setError(null);

    const prompt = `
      请作为我的私人量化顾问，对我当前的持仓进行【深度复盘审计】。
      历史悲剧警戒：
      1. 利润回撤防控 (参考 1.12 惨剧)。
      2. 2:30 尾盘确认准则。
      3. 标的精简度（严控在 3 只以内）。
      当前持仓数据：${JSON.stringify(snapshot)}
    `;

    try {
      const result = await analyzeWithLLM(currentModel, prompt, true, settings, false, 'day', undefined, currentMarket);
      setAnalysisResult(result);
    } catch (err: any) { setError(err.message); } finally { setLoading(false); }
  };

  // 还原历史快照逻辑
  const restoreFromHistory = (entry: JournalEntry) => {
    const normalizedSnapshot = { ...entry.snapshot };
    if (normalizedSnapshot.positionRatio < 1.5 && normalizedSnapshot.positionRatio > 0) {
      normalizedSnapshot.positionRatio = Number((normalizedSnapshot.positionRatio * 100).toFixed(2));
    }
    setSnapshot(normalizedSnapshot);
    setAnalysisResult(entry.analysis);
    setIsHistoryOpen(false);
    setShowSuccessTip(true);
    tableRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  return (
    <div className="space-y-6 animate-fade-in pb-20">

      {/* 核心扫描动画 Overaly */}
      {parsing && (
        <div className="fixed inset-0 z-[200] flex flex-col items-center justify-center bg-slate-900/90 backdrop-blur-xl animate-fade-in">
           <div className="relative mb-12">
              <div className="w-32 h-32 border-4 border-indigo-500/20 rounded-full animate-ping"></div>
              <div className="absolute inset-0 flex items-center justify-center">
                 <div className="w-24 h-24 border-t-4 border-indigo-500 rounded-full animate-spin"></div>
              </div>
              <div className="absolute inset-0 flex items-center justify-center">
                 <ScanSearch className="w-10 h-10 text-white animate-pulse" />
              </div>
           </div>
           <h3 className="text-2xl font-black text-white mb-3 tracking-tight">AI 持仓审计扫描中</h3>
           <p className="text-indigo-400 font-bold animate-pulse text-sm uppercase tracking-widest">{parsingPhase}</p>
        </div>
      )}

      {/* 红线警示卡片 */}
      <div className="bg-gradient-to-r from-rose-900 to-slate-900 rounded-[2.5rem] p-8 text-white shadow-2xl border-l-[12px] border-rose-500 relative overflow-hidden">
         <div className="absolute right-0 top-0 opacity-10 pointer-events-none">
            <ShieldX className="w-64 h-64 -mr-16 -mt-16" />
         </div>
         <div className="relative z-10">
            <div className="flex items-center gap-3 mb-4">
               <span className="px-3 py-1 bg-rose-600 text-white text-[10px] font-black rounded uppercase tracking-widest animate-pulse">2 月实战红线</span>
               <span className="text-slate-400 text-xs font-bold italic">“记住 1.12 的最高点回撤，不要在人声鼎沸时贪婪”</span>
            </div>
            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
               <div className="bg-white/5 backdrop-blur-md p-4 rounded-2xl border border-white/10">
                  <div className="flex items-center gap-2 text-rose-400 font-black text-xs mb-2 uppercase"><Clock className="w-4 h-4" /> 2:30 准则</div>
                  <p className="text-xs font-bold text-slate-200">早盘禁止任何冲动。必须在 **14:30** 之后定夺。</p>
               </div>
               <div className="bg-white/5 backdrop-blur-md p-4 rounded-2xl border border-white/10">
                  <div className="flex items-center gap-2 text-amber-400 font-black text-xs mb-2 uppercase"><Target className="w-4 h-4" /> 3 只上限</div>
                  <p className="text-xs font-bold text-slate-200">全账户标的严禁超过 **3 只**。确保精力集中。</p>
               </div>
               <div className="bg-white/5 backdrop-blur-md p-4 rounded-2xl border border-white/10">
                  <div className="flex items-center gap-2 text-emerald-400 font-black text-xs mb-2 uppercase"><Zap className="w-4 h-4" /> 强制止盈</div>
                  <p className="text-xs font-bold text-slate-200">最高点回撤超过 **10%** 强制止盈。防止回马枪。</p>
               </div>
            </div>
         </div>
      </div>

      {/* 控制中心 */}
      <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6 no-print">
        <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4 mb-6">
          <div>
            <h2 className="text-xl font-bold text-slate-800 flex items-center gap-2">
              <UploadCloud className="w-6 h-6 text-indigo-600" />
              持仓审计与利润守卫
            </h2>
            <p className="text-sm text-slate-500 mt-1">AI 已硬核加载您的“2:30 确认准则”与“1.12 止盈警戒线”。</p>
          </div>
          <div className="flex flex-wrap gap-2">
            <button onClick={() => setIsHistoryOpen(true)} className="flex items-center gap-2 px-3 py-2 text-sm font-bold text-slate-600 bg-slate-100 rounded-lg border border-slate-200 hover:bg-slate-200 transition-all">
              <History className="w-4 h-4" /> 历史日志
            </button>
            <input type="file" accept="image/*" ref={fileInputRef} className="hidden" onChange={handleImageUpload} />
            <button onClick={() => fileInputRef.current?.click()} className="flex items-center gap-2 px-6 py-2.5 bg-indigo-600 hover:bg-indigo-700 text-white rounded-xl font-black transition-all shadow-md active:scale-95">
              <Camera className="w-5 h-5" /> 上传最新持仓截图
            </button>
          </div>
        </div>

        {/* 成功导入提示 */}
        {showSuccessTip && (
           <div className="mb-6 p-4 bg-emerald-50 border border-emerald-100 rounded-2xl flex items-center justify-between animate-slide-down">
              <div className="flex items-center gap-3">
                 <div className="p-1.5 bg-emerald-500 rounded-full"><CheckCircle className="w-4 h-4 text-white" /></div>
                 <div>
                    <p className="text-emerald-900 font-black text-sm">持仓快照识别成功！</p>
                    <p className="text-emerald-600 text-xs font-bold">已同步 {snapshot.holdings.length} 只标的，当前资产 ¥{snapshot.totalAssets.toLocaleString()}</p>
                 </div>
              </div>
              <button onClick={() => setShowSuccessTip(false)}><X className="w-4 h-4 text-emerald-300" /></button>
           </div>
        )}

        {/* 持仓表格 */}
        <div ref={tableRef} className="overflow-x-auto rounded-xl border border-slate-200 mb-6">
           <div className="bg-slate-50 px-6 py-4 border-b border-slate-200 flex justify-between items-center">
              <div className="flex items-center gap-6">
                 <div>
                    <div className="text-[10px] text-slate-400 font-black uppercase tracking-widest">当前资产总值</div>
                    <div className="text-xl font-black text-slate-900">¥ {snapshot.totalAssets.toLocaleString()}</div>
                 </div>
                 <div className="w-px h-8 bg-slate-200"></div>
                 <div>
                    <div className="text-[10px] text-slate-400 font-black uppercase tracking-widest">标的数量</div>
                    <div className={`text-xl font-black ${snapshot.holdings.length > 3 ? 'text-rose-500' : 'text-slate-900'}`}>{snapshot.holdings.length} / 3</div>
                 </div>
              </div>
              <button onClick={() => setSnapshot({...snapshot, holdings: [...snapshot.holdings, {name: '新标的', code: '', volume:0, costPrice:0, currentPrice:0, profit:0, profitRate:'0%', marketValue:0}]})} className="text-xs font-black text-indigo-600 border border-indigo-200 px-3 py-1.5 rounded-lg hover:bg-indigo-50 transition-all">+ 手动增补</button>
           </div>
           <table className="w-full text-sm">
              <thead className="bg-slate-50 text-slate-400 text-[10px] font-black uppercase tracking-widest">
                 <tr>
                    <th className="px-6 py-3 text-left">标的名称 (代码)</th>
                    <th className="px-6 py-3">持仓成本</th>
                    <th className="px-6 py-3">盈亏情况</th>
                    <th className="px-6 py-3 text-right">操作</th>
                 </tr>
              </thead>
              <tbody className="divide-y divide-slate-100">
                 {snapshot.holdings.length === 0 ? (
                    <tr><td colSpan={4} className="py-12 text-center text-slate-400 font-bold italic">暂无数据，请上传截图或手动添加</td></tr>
                 ) : snapshot.holdings.map((item, idx) => (
                    <tr key={idx} className="hover:bg-slate-50/50 transition-colors">
                       <td className="px-6 py-4">
                          <div className="font-black text-slate-800">{item.name}</div>
                          <div className="text-[10px] font-mono text-slate-400">{item.code}</div>
                       </td>
                       <td className="px-6 py-4 text-center">
                          <div className="font-bold text-slate-700">{item.volume} 股</div>
                          <div className="text-[10px] text-slate-400">成本 ¥{item.costPrice}</div>
                       </td>
                       <td className="px-6 py-4 text-center">
                          <div className={`font-black ${item.profit >= 0 ? 'text-rose-500' : 'text-emerald-500'}`}>{item.profit >= 0 ? '+' : ''}{item.profit}</div>
                          <div className={`text-[10px] font-bold ${item.profit >= 0 ? 'text-rose-400' : 'text-emerald-400'}`}>{item.profitRate}</div>
                       </td>
                       <td className="px-6 py-4 text-right">
                          <button onClick={() => setSnapshot({...snapshot, holdings: snapshot.holdings.filter((_, i) => i !== idx)})} className="text-slate-300 hover:text-rose-500 transition-colors"><Trash2 className="w-4 h-4"/></button>
                       </td>
                    </tr>
                 ))}
              </tbody>
           </table>
        </div>

        <div className="flex justify-end">
           <button 
             onClick={handleAnalyze} 
             disabled={loading || snapshot.holdings.length === 0}
             className={`flex items-center gap-3 px-10 py-4 rounded-2xl font-black shadow-2xl transition-all active:scale-95 disabled:opacity-50 ${snapshot.holdings.length > 0 && !loading ? 'bg-indigo-600 text-white animate-pulse-subtle' : 'bg-slate-900 text-white'}`}
           >
             {loading ? <Loader2 className="w-5 h-5 animate-spin" /> : <ShieldAlert className="w-5 h-5" />}
             {loading ? 'AI 正基于血泪教训审计中...' : '启动“利润留存”实战复盘'}
           </button>
        </div>
      </div>

      {/* 审计报告展示 */}
      {analysisResult && (
        <div className="bg-white rounded-[2.5rem] border border-slate-200 shadow-sm overflow-hidden animate-slide-up">
           <div className="bg-slate-900 px-8 py-5 flex justify-between items-center">
              <div className="flex items-center gap-3">
                 <div className="p-2 bg-rose-600 rounded-lg"><Microscope className="w-5 h-5 text-white"/></div>
                 <h3 className="text-white font-black">AI 量化规则审计报告</h3>
              </div>
              <div className="flex gap-2">
                 <button onClick={() => {
                    const dataStr = JSON.stringify(snapshot, null, 2);
                    const blob = new Blob([dataStr], {type: "application/json"});
                    const url = URL.createObjectURL(blob);
                    const link = document.createElement('a');
                    link.href = url;
                    link.download = `QM_Position_${snapshot.date}.json`;
                    link.click();
                 }} className="flex items-center gap-2 px-4 py-1.5 bg-slate-800 text-white text-xs font-black rounded-lg hover:bg-slate-700 transition-all border border-slate-700">
                    <Download className="w-3.5 h-3.5" /> 导出快照
                 </button>
                 <button onClick={() => {
                    if (!analysisResult) return;
                    const newEntry: JournalEntry = { id: `jr_${Date.now()}`, timestamp: Date.now(), snapshot, analysis: analysisResult };
                    const updated = [newEntry, ...journal];
                    setJournal(updated);
                    localStorage.setItem('qm_journal', JSON.stringify(updated));
                    alert("报告已封存。");
                 }} className="flex items-center gap-2 px-4 py-1.5 bg-indigo-600 text-white text-xs font-black rounded-lg hover:bg-indigo-700 transition-all border border-indigo-500">
                    <Save className="w-3.5 h-3.5" /> 封存至历史日志
                 </button>
              </div>
           </div>
           <div className="p-10 prose prose-slate max-w-none">
              <div dangerouslySetInnerHTML={{ __html: analysisResult.content.replace(/\n/g, '<br/>').replace(/##\s+(.*)/g, '<h2 class="text-2xl font-black text-slate-800 border-b-2 border-slate-100 pb-3 mt-8 mb-4">$1</h2>') }} />
           </div>
        </div>
      )}

      {/* 历史记录 Modal (Reuse optimized version from previous logic) */}
      {isHistoryOpen && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-md animate-fade-in">
           <div className="bg-white rounded-[2.5rem] shadow-2xl w-full max-w-4xl max-h-[85vh] overflow-hidden flex flex-col">
              <div className="px-8 py-6 border-b border-slate-100 bg-slate-50 flex justify-between items-center">
                 <div>
                    <h3 className="text-xl font-black text-slate-800 flex items-center gap-3">
                        <History className="w-6 h-6 text-indigo-600" />
                        实战审计黑匣子
                    </h3>
                 </div>
                 <div className="flex gap-2">
                    <button onClick={() => setIsImportTextOpen(true)} className="flex items-center gap-2 px-4 py-2 bg-white text-slate-700 rounded-xl text-xs font-black border border-slate-200">导入文本</button>
                    <button onClick={() => setIsHistoryOpen(false)} className="p-2 text-slate-400 hover:text-slate-600 transition-colors ml-4"><X className="w-6 h-6" /></button>
                 </div>
              </div>
              <div className="p-8 overflow-y-auto flex-1 bg-slate-50/50">
                 {journal.length === 0 ? (
                    <div className="py-20 text-center flex flex-col items-center gap-4 text-slate-400 font-bold">暂无历史。</div>
                 ) : (
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                       {journal.map((entry) => (
                          <div key={entry.id} className="group p-6 bg-white rounded-[2rem] border border-slate-200 hover:border-indigo-400 hover:shadow-xl transition-all flex flex-col justify-between">
                             <div className="mb-4">
                                <div className="flex justify-between items-start mb-4">
                                   <div className="text-center bg-indigo-50 w-14 h-14 rounded-2xl border border-indigo-100 flex flex-col justify-center">
                                      <div className="text-[10px] font-black text-indigo-400">{new Date(entry.timestamp).getMonth()+1}月</div>
                                      <div className="text-xl font-black text-indigo-600">{new Date(entry.timestamp).getDate()}</div>
                                   </div>
                                   <div className="text-right">
                                      <div className="text-sm font-black text-slate-800">¥ {entry.snapshot?.totalAssets?.toLocaleString() || '0'}</div>
                                      <div className="text-[10px] font-bold text-slate-400">{entry.snapshot?.date}</div>
                                   </div>
                                </div>
                             </div>
                             <div className="flex gap-2">
                                <button onClick={() => restoreFromHistory(entry)} className="flex-1 py-2.5 bg-indigo-600 text-white text-xs font-black rounded-xl hover:bg-indigo-700 transition-all flex items-center justify-center gap-2">还原对比 <ChevronRight className="w-4 h-4" /></button>
                                <button onClick={() => {
                                    const updated = journal.filter(j => j.id !== entry.id);
                                    setJournal(updated);
                                    localStorage.setItem('qm_journal', JSON.stringify(updated));
                                }} className="p-2.5 text-slate-300 hover:text-rose-500 bg-slate-50 rounded-xl border border-slate-100"><Trash2 className="w-4 h-4" /></button>
                             </div>
                          </div>
                       ))}
                    </div>
                 )}
              </div>
           </div>
        </div>
      )}

      {/* 粘贴导入 Modal */}
      {isImportTextOpen && (
        <div className="fixed inset-0 z-[110] flex items-center justify-center p-4 bg-slate-900/40 backdrop-blur-sm">
           <div className="bg-white rounded-[2.5rem] shadow-2xl w-full max-w-2xl p-8">
              <h3 className="text-lg font-black text-slate-800 mb-4">直接粘贴 JSON 同步</h3>
              <textarea 
                value={importText} 
                onChange={e => setImportText(e.target.value)}
                placeholder="粘贴 1 月份日志 JSON..."
                className="w-full h-64 p-4 bg-slate-50 border border-slate-200 rounded-2xl font-mono text-xs outline-none"
              />
              <div className="mt-6 flex gap-3">
                 <button onClick={() => {
                    try {
                      const json = JSON.parse(importText);
                      const rawArray = Array.isArray(json) ? json : [json];
                      const normalized = rawArray.map(item => {
                        const newItem = { ...item };
                        if (newItem.snapshot && newItem.snapshot.positionRatio < 1.5) {
                          newItem.snapshot.positionRatio = Number((newItem.snapshot.positionRatio * 100).toFixed(2));
                        }
                        return newItem as JournalEntry;
                      });
                      const combined = [...normalized, ...journal].filter((v, i, a) => a.findIndex(t => t.id === v.id) === i);
                      setJournal(combined);
                      localStorage.setItem('qm_journal', JSON.stringify(combined));
                      setImportText('');
                      setIsImportTextOpen(false);
                      alert("同步成功。");
                    } catch (e) { alert("JSON 格式错误。"); }
                 }} className="flex-1 py-4 bg-indigo-600 text-white font-black rounded-2xl">同步数据</button>
                 <button onClick={() => setIsImportTextOpen(false)} className="px-8 py-4 bg-slate-100 text-slate-600 font-black rounded-2xl">取消</button>
              </div>
           </div>
        </div>
      )}
    </div>
  );
};
